const readline = require('readline');

const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

function main() {
    let input = '';

    // Read data from stdin
    rl.on('line', (line) => {
        input += line + '\n'; // Accumulate input
    });

    rl.on('close', () => {
        // Split the accumulated input into lines
        const lines = input.trim().split('\n');

        // Parse the number of elements
        const n = parseInt(lines[0].trim(), 10);

        // Parse the array elements
        const arr = lines[1].trim().split(' ').map(Number);

        // Find the leaders
        const leaders = [];
        let maxFromRight = arr[n - 1]; // Start with the last element as a leader
        leaders.push(maxFromRight);

        // Traverse the array from right to left
        for (let i = n - 2; i >= 0; i--) {
            if (arr[i] > maxFromRight) {
                maxFromRight = arr[i];
                leaders.push(maxFromRight);
            }
        }

        // Print leaders in the same order as they appear from left to right
        console.log(leaders.reverse().join(' '));
    });
}

